//import axios from 'axios';
import React, { useState, useEffect, useContext } from 'react';
import { Nav } from 'react-bootstrap';
import { useHistory, useParams } from 'react-router-dom';
import styled from 'styled-components';
import './Detail.scss';
import { 재고context } from './App.js';

import { CSSTransition } from 'react-transition-group';
import { connect } from 'react-redux';

let 박스 = styled.div`
    padding : 20ex;
`;
let 제목 = styled.h4`
    font-size: 25px;
    color : ${ props => props.색상 };
`;

function Detail(props) {
    let [alert, alert변경] = useState(true);
    let [alert메세지, alert메세지변경] = useState('재고가 얼마 남지 않았습니다');
    //let [inputData, inputData변경] = useState('');
    let 재고 = useContext(재고context);
    let [누른탭, 누른탭변경] = useState(0);
    let [스위치, 스위치변경] = useState(false);
    let [주문수량, 주문수량변경] = useState(0);
    let 사이즈리스트 = [ 
        { value: '선택', label: '선택'},
        { value: 245, label: '245' },
        { value: 250, label: '250' },
        { value: 255, label: '255' },
        { value: 260, label: '260' },
        { value: 265, label: '265' },
        { value: 270, label: '270' },
        { value: 275, label: '275' },
        { value: 280, label: '280' },
        { value: 285, label: '285' },
        { value: 290, label: '290' },
     ];
     let [사이즈, 사이즈변경] = useState('선택');

    useEffect(() => {
        //axios.get()
        
        // 2초 후에 alert 창을 안보이게 하기
        let timer = setTimeout(() => {alert변경(false)},5000);
        return () =>{ clearTimeout(timer) };
    },[alert]);

    let { id } = useParams();
    let history = useHistory();

    let 찾은상품 = props.shoes.find(x => x.id == id);

    return (
        <div className="container">
            <박스>
                <제목 className="red">Detail</제목>
            </박스>
            {/* {inputData}
            <input onChange={(e) => {inputData변경(e.target.value)}}/>             */}
            {
                (alert === true) ? 
                (<div className="my-alert2">
                    <p>{alert메세지}</p>
                </div>) : null
            }
            
            <div className="row">
                <div className="col-md-6">
                    <img src={'https://codingapple1.github.io/shop/shoes' + (parseInt(찾은상품.id) +1) + '.jpg'} width="100%" />
                </div>
                <div className="col-md-6 mt-4">
                    <h4 className="pt-5">{찾은상품.title}</h4>
                    <p>{찾은상품.content}</p>
                    <p>{찾은상품.price}원</p>

                    <Info 재고={재고}></Info>
                    <p>사이즈 : <select onChange={(e) => 사이즈변경(e.target.value)} value={사이즈}>
                        {사이즈리스트.map(({ value, label }, index) => <option value={value}>{label}</option>)}
                        </select>
                    </p>
                    <p>주문수량 : <input onChange={(e) => {주문수량변경(e.target.value)}} value={주문수량}/></p>
                    <button className="btn btn-danger" onClick={() => { 
                            props.재고변경([9,11,12]);
                            if(사이즈 == '선택'){
                                alert메세지변경('사이즈를 선택해주세요.');
                                alert변경(true);
                                return;
                            }
                            if(주문수량 === 0){
                                alert메세지변경('주문수량을 입력해주세요.');
                                alert변경(true);
                                return;
                            }

                            props.dispatch({ type: '항목추가' , 데이터 : {id : 찾은상품.id, name: 찾은상품.title, size:사이즈 , quan: 주문수량}});
                            history.push('/cart');
                        }}>주문하기</button>
                    &nbsp;
                    <button className="btn btn-danger" onClick={() => {
                        //history.goBack();
                        history.push('/')
                    }}>뒤로가기</button>
                </div>
            </div>
            <Nav className="mt-5" variant="tabs" defaultActiveKey="/link-0">
                <Nav.Item>
                    <Nav.Link eventKey="link-0" onClick={() => {스위치변경(false); 누른탭변경(0)}}>상품설명</Nav.Link>
                </Nav.Item>
                <Nav.Item>
                    <Nav.Link eventKey="link-1" onClick={() => {스위치변경(false); 누른탭변경(1)}}>배송정보</Nav.Link>
                </Nav.Item>
            </Nav>
            <CSSTransition in={스위치} classNames="wow" timeout={500}>
                <TabContent 누른탭={누른탭} 스위치변경={스위치변경}/>
            </CSSTransition>
        </div>
    );
}

function TabContent(props){
    useEffect(() => {
        props.스위치변경(true);
    })

    if(props.누른탭 === 0){
        return <div>0번째 내용입니다</div>
    } else if (props.누른탭 === 1){
        return <div>1번째 내용입니다</div>
    } else if (props.누른탭 === 2){
        return <div>2번째 내용입니다</div>
    }
}

function Info(props){
    return(
        <p>재고 : {props.재고[1]}</p>
    );
}

function state를props화(state){
    console.log(state);
    return {
        state : state.reducer,
        alert열렸니 : state.reducer
    }
}

export default connect(state를props화)(Detail);